import { Injectable, signal, computed } from '@angular/core';

export interface NpkData {
  n: number;
  p: number;
  k: number;
  timestamp: Date | null;
}

export interface TankData {
  methane: number; // ppm
  temperature: number; // Celsius
  humidity: number; // %
  ph: number;
}

export interface SoilType {
  id: string;
  name: string;
  description: string;
  deficiencies: string[];
}

export interface Fertilizer {
  name: string;
  n: number;
  p: number;
  k: number;
  description: string;
}

@Injectable({
  providedIn: 'root'
})
export class DataService {
  // --- Hardware State ---
  isConnected = signal<boolean>(false); // Mock NPK connection
  isSerialConnected = signal<boolean>(false); // Real Arduino Serial connection

  npkReadings = signal<NpkData>({ n: 0, p: 0, k: 0, timestamp: null });
  tankReadings = signal<TankData>({ methane: 0, temperature: 0, humidity: 0, ph: 7.0 });

  // --- Database ---
  readonly soils: SoilType[] = [
    { id: 'red', name: 'Red Soil', description: 'Rich in iron, porous structure. Common in Tamil Nadu.', deficiencies: ['Nitrogen', 'Humus', 'Lime'] },
    { id: 'black', name: 'Black Cotton Soil', description: 'High clay content, retains moisture well.', deficiencies: ['Nitrogen', 'Phosphorus', 'Organic Matter'] },
    { id: 'alluvial', name: 'Alluvial Soil', description: 'Very fertile, found in river deltas.', deficiencies: ['Nitrogen', 'Humus'] }
  ];

  readonly fertilizers: Fertilizer[] = [
    { name: 'Vermicompost', n: 2, p: 1, k: 1, description: 'Excellent all-rounder organic fertilizer.' },
    { name: 'Cow Dung Manure', n: 0.6, p: 0.2, k: 0.5, description: 'Traditional base fertilizer.' },
    { name: 'Neem Cake', n: 5, p: 1, k: 1.5, description: 'High Nitrogen, also acts as pest repellent.' },
    { name: 'Bone Meal', n: 3, p: 20, k: 0, description: 'Rich in Phosphorus for root growth.' },
    { name: 'Wood Ash', n: 0, p: 1, k: 10, description: 'Rich in Potassium.' }
  ];

  constructor() {
    this.startTankMonitoring();
  }

  // --- Actions ---

  async connectToDevice(): Promise<boolean> {
    // Simulating a handshake with ESP32 via local IP or Bluetooth for NPK
    return new Promise((resolve) => {
      setTimeout(() => {
        this.isConnected.set(true);
        resolve(true);
      }, 1500);
    });
  }

  async readNPK(): Promise<void> {
    if (!this.isConnected()) return;

    // Simulate reading from ESP32 sensors
    return new Promise((resolve) => {
      setTimeout(() => {
        this.npkReadings.set({
          n: Math.floor(Math.random() * (200 - 20) + 20), // mg/kg
          p: Math.floor(Math.random() * (100 - 10) + 10),
          k: Math.floor(Math.random() * (300 - 50) + 50),
          timestamp: new Date()
        });
        resolve();
      }, 800);
    });
  }

  // --- Web Serial for Tank Monitor ---
  async connectSerial() {
    if (!('serial' in navigator)) {
      alert('Web Serial API not supported in this browser. Try Chrome or Edge.');
      return;
    }

    try {
      // Request a port and open a connection.
      const port = await (navigator as any).serial.requestPort();
      await port.open({ baudRate: 9600 });

      this.isSerialConnected.set(true);
      this.readSerialLoop(port);
    } catch (error) {
      console.error('There was an error opening the serial port:', error);
      this.isSerialConnected.set(false);
    }
  }

  private async readSerialLoop(port: any) {
    const textDecoder = new TextDecoderStream();
    const readableStreamClosed = port.readable.pipeTo(textDecoder.writable);
    const reader = textDecoder.readable.getReader();
    let buffer = '';

    try {
      while (true) {
        const { value, done } = await reader.read();
        if (done) {
          // Allow the serial port to be closed later.
          reader.releaseLock();
          break;
        }
        if (value) {
          buffer += value;
          const lines = buffer.split('\n');
          // Process all complete lines
          for (let i = 0; i < lines.length - 1; i++) {
             this.parseSerialData(lines[i]);
          }
          // Keep the remainder in buffer
          buffer = lines[lines.length - 1];
        }
      }
    } catch (error) {
      console.error('Serial Read Error:', error);
      this.isSerialConnected.set(false);
    }
  }

  private parseSerialData(line: string) {
    try {
      const jsonStr = line.trim();
      if (!jsonStr) return;

      // Expecting JSON: {"methane": 123, "temperature": 28.5, "humidity": 60}
      const data = JSON.parse(jsonStr);

      this.tankReadings.update(current => ({
        ...current,
        // Update real values if present, keep old if not
        methane: typeof data.methane === 'number' ? data.methane : current.methane,
        temperature: typeof data.temperature === 'number' ? data.temperature : current.temperature,
        humidity: typeof data.humidity === 'number' ? data.humidity : current.humidity,
        // pH is NOT updated from Serial as per requirements
      }));
    } catch (e) {
      // Ignore parse errors (incomplete lines etc)
      console.debug('Invalid JSON from serial:', line);
    }
  }

  private startTankMonitoring() {
    // Background loop
    setInterval(() => {
      // Always simulate pH as it is not available from Arduino
      const newPh = parseFloat((Math.random() * (8.5 - 5.5) + 5.5).toFixed(2));

      if (this.isSerialConnected()) {
        // If Serial is connected, ONLY update pH via simulation.
        // Methane, Temp, Humidity come from Serial.
        this.tankReadings.update(curr => ({ ...curr, ph: newPh }));
      } 
      else if (this.isConnected()) {
        // If only NPK Mock is connected, we simulate everything for demo purposes
        this.tankReadings.set({
          methane: parseFloat((Math.random() * (500 - 100) + 100).toFixed(1)),
          temperature: parseFloat((Math.random() * (35 - 25) + 25).toFixed(1)),
          humidity: parseFloat((Math.random() * (90 - 40) + 40).toFixed(1)),
          ph: newPh
        });
      }
    }, 3000);
  }
}

