import { Injectable, signal, computed } from '@angular/core';

export interface NpkData {
  n: number;
  p: number;
  k: number;
  timestamp: Date | null;
}

export interface TankData {
  methane: number; // Raw Analog Value (approx ppm)
  temperature: number; // Celsius
  humidity: number; // %
  ph: number;
}

export interface SoilType {
  id: string;
  name: string;
  description: string;
