#include <DHT.h>

// -------- PIN DEFINITIONS --------
#define DHTPIN 2
#define DHTTYPE DHT11

#define MQ4_DIGITAL_PIN 3
#define MQ4_ANALOG_PIN A0

#define RELAY1_PIN 4
#define RELAY2_PIN 5

// -------- OBJECTS --------
DHT dht(DHTPIN, DHTTYPE);

// -------- VARIABLES --------
float temperature;
float humidity;
int gasAnalog;
int gasDigital;

bool relay1State = false; // false = OFF
bool relay2State = false; // false = OFF

void setup() {
  Serial.begin(9600);

  pinMode(RELAY1_PIN, OUTPUT);
  pinMode(RELAY2_PIN, OUTPUT);
  pinMode(MQ4_DIGITAL_PIN, INPUT);

  // Relays OFF initially (Active LOW)
  digitalWrite(RELAY1_PIN, HIGH);
  digitalWrite(RELAY2_PIN, HIGH);

  dht.begin();

  Serial.println("System Initialized");
  Serial.println("Commands: R1ON, R1OFF, R2ON, R2OFF, STATUS");
}

void loop() {
  // -------- READ DHT11 --------
  humidity = dht.readHumidity();
  temperature = dht.readTemperature();

  // -------- READ MQ-4 --------
  gasAnalog = analogRead(MQ4_ANALOG_PIN);
  gasDigital = digitalRead(MQ4_DIGITAL_PIN);

  // -------- DISPLAY SENSOR DATA --------
  Serial.print("Temp: ");
  Serial.print(temperature);
  Serial.print(" °C | Humidity: ");
  Serial.print(humidity);
  Serial.print(" % | MQ4 Analog: ");
  Serial.print(gasAnalog);
  Serial.print(" | MQ4 Digital: ");
  Serial.println(gasDigital);

  // -------- SERIAL RELAY CONTROL --------
  if (Serial.available()) {
    String cmd = Serial.readStringUntil('\n');
    cmd.trim();

    if (cmd == "R1ON") {
      relay1State = true;
      digitalWrite(RELAY1_PIN, LOW);
      Serial.println("Relay 1 ON");
    }
    else if (cmd == "R1OFF") {
      relay1State = false;
      digitalWrite(RELAY1_PIN, HIGH);
      Serial.println("Relay 1 OFF");
    }
    else if (cmd == "R2ON") {
      relay2State = true;
      digitalWrite(RELAY2_PIN, LOW);
      Serial.println("Relay 2 ON");
    }
    else if (cmd == "R2OFF") {
      relay2State = false;
      digitalWrite(RELAY2_PIN, HIGH);
      Serial.println("Relay 2 OFF");
    }
    else if (cmd == "STATUS") {
      Serial.print("Relay 1: ");
      Serial.println(relay1State ? "ON" : "OFF");
      Serial.print("Relay 2: ");
      Serial.println(relay2State ? "ON" : "OFF");
    }
  }

  delay(2000);
}
