export class PlantAnalyserComponent {
  imagePreview = signal<string | null>(null);
  isLoading = signal<boolean>(false);
  error = signal<string | null>(null);
  result = signal<AnalysisResult | null>(null);

  handleImage(event: Event) {
    const input = event.target as HTMLInputElement;
    if (input.files && input.files[0]) {
      const file = input.files[0];
      const reader = new FileReader();
      reader.onload = (e) => {
        this.imagePreview.set(e.target?.result as string);
        this.result.set(null);
        this.error.set(null);
      };
      reader.readAsDataURL(file);
    }
  }

  clearImage() {
    this.imagePreview.set(null);
    this.result.set(null);
    this.error.set(null);
  }

  async analyzePlant() {
    const imageData = this.imagePreview();
    if (!imageData) return;

    this.isLoading.set(true);
    this.error.set(null);

    try {
      // 1. Safe Env Access: Prevent crash if process is undefined in browser
      let apiKey = '';
      try {
        apiKey = process.env.API_KEY || '';
      } catch (e) {
        throw new Error('System Configuration Error: API_KEY is missing (process not defined).');
      }

      if (!apiKey) {
        throw new Error('API Key is missing in configuration.');
      }

      // 2. Prepare Data
      const base64Data = imageData.split(',')[1];
      const mimeType = imageData.substring(imageData.indexOf(':') + 1, imageData.indexOf(';'));

      const ai = new GoogleGenAI({ apiKey });

      const prompt = `
        Act as an expert agricultural agronomist. Analyze this image of a plant.
        Identify the crop name.
        Detect any diseases, pests, visible stress symptoms, or nutrient deficiencies.

        Suggest specific treatments (organic and chemical) and specific product names available in India.
      `;

      // 3. Define Schema for strict JSON
      const schema = {
        type: Type.OBJECT,
        properties: {
          cropName: { type: Type.STRING },
          condition: { type: Type.STRING },
          status: { type: Type.STRING, enum: ["Healthy", "Attention Required", "Critical"] },
          confidence: { type: Type.NUMBER },
          symptoms: { type: Type.ARRAY, items: { type: Type.STRING } },
          deficiencies: { type: Type.ARRAY, items: { type: Type.STRING } },
          treatments: {
            type: Type.OBJECT,
            properties: {
              organic: { type: Type.ARRAY, items: { type: Type.STRING } },
              chemical: { type: Type.ARRAY, items: { type: Type.STRING } }
            }
          },
          recommendedProducts: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                type: { type: Type.STRING }
              }
            }
          },
          prevention: { type: Type.ARRAY, items: { type: Type.STRING } }
        },
        required: ["cropName", "status", "condition", "treatments"]
      };

      // 4. API Call
      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: [
          {
            parts: [
              { text: prompt },
              { inlineData: { mimeType: mimeType, data: base64Data } }
            ]
          }
        ],
        config: {
          responseMimeType: 'application/json',
          responseSchema: schema
        }
      });

      // 5. Safe Parsing
      const jsonText = response.text;
      if (jsonText) {
        const data = JSON.parse(jsonText);
        this.result.set(data);
      } else {
        throw new Error('No analysis data received from AI.');
      }

    } catch (err: any) {
      console.error('Analysis Error:', err);
      // More user friendly error messages
      let msg = 'Failed to analyze image. Please try again.';
      if (err.message.includes('API_KEY')) msg = 'Configuration Error: API Key missing.';
      if (err.message.includes('fetch')) msg = 'Network Error: Please check your internet connection.';

      this.error.set(msg);
    } finally {
      // 6. Ensure Loading stops
      this.isLoading.set(false);
    }
  }

  getAmazonLink(query: string): string {
    return `https://www.amazon.in/s?k=${encodeURIComponent(query + ' agriculture')}`;
  }

  getFlipkartLink(query: string): string {
    return `https://www.flipkart.com/search?q=${encodeURIComponent(query + ' agriculture')}`;
  }
}

