#include <DHT.h>
// --- Pin Definitions (Your Config) ---
#define DHTPIN 2 // D2
#define DHTTYPE DHT11
// MQ4
#define MQ4_DIGITAL 3 // D3
#define MQ4_ANALOG A0 // A0
// Relay
#define RELAY_PIN 4 // D4
// Motor A
#define IN1 6 // D6
#define IN2 7 // D7
#define ENA 11 // D11 (PWM)
// Motor B
#define IN3 8 // D8
#define IN4 9 // D9
#define ENB 10 // D10 (PWM)
// --- Objects ---
DHT dht(DHTPIN, DHTTYPE);
// --- Variables ---
unsigned long lastMsg = 0;
void setup() {
Serial.begin(9600); // Communication speed
// Initialize Pins
pinMode(MQ4_DIGITAL, INPUT);
pinMode(RELAY_PIN, OUTPUT);
pinMode(IN1, OUTPUT); pinMode(IN2, OUTPUT); pinMode(ENA, OUTPUT);
pinMode(IN3, OUTPUT); pinMode(IN4, OUTPUT); pinMode(ENB, OUTPUT);
dht.begin();
// Default Relay OFF
digitalWrite(RELAY_PIN, HIGH);
}
void loop() {
// 1. Listen for Commands from Computer
if (Serial.available() > 0) {
String command = Serial.readStringUntil('\n');
parseCommand(command);
}
// 2. Send Sensor Data to Computer every 2 seconds
if (millis() - lastMsg > 2000) {
lastMsg = millis();
readAndSendSensors();
}
}
void readAndSendSensors() {
float h = dht.readHumidity();
float t = dht.readTemperature();
int gasRaw = analogRead(MQ4_ANALOG);
int gasAlarm = digitalRead(MQ4_DIGITAL);
if (isnan(h) || isnan(t)) {
h = 0; t = 0;
}
// Format: JSON string for easy parsing by the website
Serial.print("{"t":"); Serial.print(t);
Serial.print(","h":"); Serial.print(h);
Serial.print(","g":"); Serial.print(gasRaw);
Serial.print(","a":"); Serial.print(gasAlarm);
Serial.println("}");
}
void parseCommand(String cmd) {
// Command Format Expected: "MOTOR:A:F:200" or "RELAY:1"
if (cmd.startsWith("RELAY")) {
int state = cmd.substring(6).toInt(); // Get value after "RELAY:"
digitalWrite(RELAY_PIN, state == 1 ? LOW : HIGH); // Active LOW assumption
}
else if (cmd.startsWith("MOTOR")) {
// format: MOTOR:A:F:255
char motor = cmd.charAt(6); // 'A' or 'B'
char dir = cmd.charAt(8); // 'F', 'B', 'S'
int speed = cmd.substring(10).toInt();
if (motor == 'A') controlMotor(ENA, IN1, IN2, dir, speed);
if (motor == 'B') controlMotor(ENB, IN3, IN4, dir, speed);
}
}
void controlMotor(int en, int i1, int i2, char d, int s) {
if (d == 'F') {
digitalWrite(i1, HIGH); digitalWrite(i2, LOW); analogWrite(en, s);
} else if (d == 'B') {
digitalWrite(i1, LOW); digitalWrite(i2, HIGH); analogWrite(en, s);
} else {
digitalWrite(i1, LOW); digitalWrite(i2, LOW); analogWrite(en, 0);
}
