export class TankMonitorComponent {
  dataService = inject(DataService);

  getPhStatus(ph: number): string {
    if (ph < 6.0) return 'ACIDIC';
    if (ph > 7.5) return 'ALKALINE';
    return 'NEUTRAL';
  }

  async connectUsb() {
    await this.dataService.connectTank();
  }
}

