#include <ModbusMaster.h>

// -------- PIN CONFIG --------
#define RX2_PIN 16
#define TX2_PIN 17
#define RE_PIN 25
#define DE_PIN 26

ModbusMaster node;

// -------- RS485 CONTROL --------
void preTransmission() {
  digitalWrite(RE_PIN, HIGH);
  digitalWrite(DE_PIN, HIGH);
  delay(5);
}

void postTransmission() {
  delay(5);
  digitalWrite(RE_PIN, LOW);
  digitalWrite(DE_PIN, LOW);
}

void setup() {

  Serial.begin(115200);        // USB communication to App
  Serial2.begin(9600, SERIAL_8N1, RX2_PIN, TX2_PIN);  // RS485

  pinMode(RE_PIN, OUTPUT);
  pinMode(DE_PIN, OUTPUT);

  digitalWrite(RE_PIN, LOW);
  digitalWrite(DE_PIN, LOW);

  node.begin(1, Serial2);   // Default Slave ID = 1
  node.preTransmission(preTransmission);
  node.postTransmission(postTransmission);

  delay(2000);
}

// -------- MAIN LOOP --------
void loop() {

  uint8_t result;
  result = node.readHoldingRegisters(0x001E, 3);

  if (result == node.ku8MBSuccess) {

    uint16_t nitrogen   = node.getResponseBuffer(0);
    uint16_t phosphorus = node.getResponseBuffer(1);
    uint16_t potassium  = node.getResponseBuffer(2);

    // 🔹 Structured Data Format (Easy for App Parsing)
    Serial.print("N:");
    Serial.print(nitrogen);
    Serial.print(",P:");
    Serial.print(phosphorus);
    Serial.print(",K:");
    Serial.println(potassium);

  } else {

    // Send error code to app
    Serial.print("ERROR:");
    Serial.println(result, HEX);
  }

  delay(3000);
}
