#include <ModbusMaster.h>

// ================= PIN DEFINITIONS =================
#define RX2_PIN 16  // RO on RS485 Module
#define TX2_PIN 17  // DI on RS485 Module
#define RE_PIN 25   // RE on RS485 Module
#define DE_PIN 26   // DE on RS485 Module

ModbusMaster node;

void preTransmission() {
  digitalWrite(RE_PIN, HIGH);
  digitalWrite(DE_PIN, HIGH);
  delay(5); // Stabilization time
}

void postTransmission() {
  delay(5); // Wait for data to fully leave UART
  digitalWrite(RE_PIN, LOW);
  digitalWrite(DE_PIN, LOW);
}

void setup() {
  // 1. Initialize USB Serial (Must match Angular: 9600)
  Serial.begin(9600);

  // 2. Initialize RS485 Serial (Sensor usually 9600 or 4800)
  Serial2.begin(9600, SERIAL_8N1, RX2_PIN, TX2_PIN);

  // 3. Configure RS485 Control Pins
  pinMode(RE_PIN, OUTPUT);
  pinMode(DE_PIN, OUTPUT);
  digitalWrite(RE_PIN, LOW);
  digitalWrite(DE_PIN, LOW);

  // 4. Init Modbus
  node.begin(1, Serial2); // Slave ID 1
  node.preTransmission(preTransmission);
  node.postTransmission(postTransmission);
}

void loop() {
  // Check for command from Angular App (Optional, but good for responsiveness)
  if (Serial.available()) {
    String cmd = Serial.readStringUntil('\n');
    cmd.trim();
    if (cmd == "READ_NPK") {
      readAndSendSensor();
    }
  }

  // Also read periodically every 2 seconds
  static unsigned long lastRun = 0;
  if (millis() - lastRun > 2000) {
    readAndSendSensor();
    lastRun = millis();
  }
}

void readAndSendSensor() {
  uint8_t result;

  // Read 3 registers starting at 0x1E (Nitrogen, Phos, Potassium)
  // Note: Register address depends on your specific NPK sensor model (JXBS-3001 etc)
  result = node.readHoldingRegisters(0x001E, 3);

  if (result == node.ku8MBSuccess) {
    uint16_t nitrogen   = node.getResponseBuffer(0);
    uint16_t phosphorus = node.getResponseBuffer(1);
    uint16_t potassium  = node.getResponseBuffer(2);

    // Format matches Angular Regex: /N:(\d+),P:(\d+),K:(\d+)/
    Serial.print("N:");
    Serial.print(nitrogen);
    Serial.print(",P:");
    Serial.print(phosphorus);
    Serial.print(",K:");
    Serial.println(potassium);
  } else {
    // Debugging (Angular ignores lines not matching N:x,P:x,K:x)
    // Serial.print("Modbus Error: ");
    // Serial.println(result, HEX);
  }
}
