### 2. Tank & Motor Controller (`Tank_Motor_Control.ino`)
*Upload this to the ESP32 connected to the **Relays, Motors, and Tank Sensors**.*

This code handles the JSON telemetry for the dashboard and parses the specific commands sent by the `DataService`.

```cpp
#include <Arduino.h>
#include <DHT.h>

// ================= PIN DEFINITIONS =================

// --- Sensors ---
#define DHT_PIN       4     // DHT11 or DHT22 Data Pin
#define GAS_PIN       34    // Analog Input (MQ-4 Methane)
#define PH_PIN        35    // Analog Input (pH Sensor)

// --- Actuators (Relays) ---
#define HEATER_RELAY  25    // Relay Module IN pin

// --- Motor A (Grinder) - L298N ---
#define ENA_PIN       14    // PWM Speed
#define IN1_PIN       27    // Direction 1
#define IN2_PIN       26    // Direction 2

// --- Motor B (Agitator) - L298N ---
#define ENB_PIN       32    // PWM Speed
#define IN3_PIN       33    // Direction 1
#define IN4_PIN       25    // Direction 2 (Be careful: 25 used for Heater above? Reassigning)
// RE-MAPPING TO AVOID CONFLICT:
#undef HEATER_RELAY
#define HEATER_RELAY  23    // Changed Heater to GPIO 23

// ================= CONFIGURATION =================
#define DHT_TYPE      DHT11 // Change to DHT22 if needed
#define BAUD_RATE     9600  // Must match Angular App

DHT dht(DHT_PIN, DHT_TYPE);

// PWM Properties
const int freq = 30000;
const int pwmChannelA = 0;
const int pwmChannelB = 1;
const int resolution = 8;

void setup() {
  Serial.begin(BAUD_RATE);
  dht.begin();

  // --- Pin Modes ---
  pinMode(HEATER_RELAY, OUTPUT);
  pinMode(IN1_PIN, OUTPUT);
  pinMode(IN2_PIN, OUTPUT);
  pinMode(IN3_PIN, OUTPUT);
  pinMode(IN4_PIN, OUTPUT); // Note: 25 was originally Heater, ensure wiring matches new map

  // --- PWM Setup (ESP32) ---
  ledcAttachPin(ENA_PIN, pwmChannelA);
  ledcSetup(pwmChannelA, freq, resolution);

  ledcAttachPin(ENB_PIN, pwmChannelB);
  ledcSetup(pwmChannelB, freq, resolution);

  // --- Initial State (OFF) ---
  digitalWrite(HEATER_RELAY, LOW); // Assuming Active HIGH Relay
  stopMotorA();
  stopMotorB();
}

void loop() {
  // 1. Handle Incoming Commands from Angular
  if (Serial.available()) {
    String command = Serial.readStringUntil('\n');
    command.trim();
    parseCommand(command);
  }

  // 2. Send Telemetry periodically (every 2 seconds)
  static unsigned long lastMsg = 0;
  if (millis() - lastMsg > 2000) {
    sendTelemetry();
    lastMsg = millis();
  }
}

// ================= COMMAND PARSING =================
// Angular Format: 
// RELAY:1 or RELAY:0
// MOTOR:A:F:255 (Motor Char, Dir Char, Speed Int)
void parseCommand(String cmd) {
  if (cmd.startsWith("RELAY:")) {
    int state = cmd.substring(6).toInt();
    digitalWrite(HEATER_RELAY, state ? HIGH : LOW);
    // Serial.println("ACK:RELAY_UPDATED");
  } 
  else if (cmd.startsWith("MOTOR:")) {
    // Expected: MOTOR:A:F:255
    char motorID = cmd.charAt(6);   // 'A' or 'B'
    char dir     = cmd.charAt(8);   // 'F', 'B', 'S'
    int speed    = cmd.substring(10).toInt();

    if (motorID == 'A') {
      controlMotor(1, dir, speed);
    } else if (motorID == 'B') {
      controlMotor(2, dir, speed);
    }
  }
}

// ================= MOTOR CONTROL =================
void controlMotor(int motorId, char dir, int speed) {
  int ch = (motorId == 1) ? pwmChannelA : pwmChannelB;
  int p1 = (motorId == 1) ? IN1_PIN : IN3_PIN;
  int p2 = (motorId == 1) ? IN2_PIN : IN4_PIN;

  ledcWrite(ch, speed);

  if (dir == 'F') {
    digitalWrite(p1, HIGH);
    digitalWrite(p2, LOW);
  } else if (dir == 'B') {
    digitalWrite(p1, LOW);
    digitalWrite(p2, HIGH);
  } else {
    // Stop
    digitalWrite(p1, LOW);
    digitalWrite(p2, LOW);
    ledcWrite(ch, 0);
  }
}

void stopMotorA() { controlMotor(1, 'S', 0); }
void stopMotorB() { controlMotor(2, 'S', 0); }

// ================= TELEMETRY =================
void sendTelemetry() {
  // Read Sensors
  float t = dht.readTemperature();
  float h = dht.readHumidity();

  // Read Analog (0-4095)
  int gasRaw = analogRead(GAS_PIN);
  int phRaw = analogRead(PH_PIN);

  // Basic conversions (Calibrate these for real hardware!)
  float methane = map(gasRaw, 0, 4095, 0, 1000); // approx ppm
  // pH calculation (Assuming standard probe: 2.5V center @ pH 7)
  float voltage = phRaw * (3.3 / 4095.0);
  float ph = 7.0 + ((2.5 - voltage) / 0.18); 

  if (isnan(t)) t = 0;
  if (isnan(h)) h = 0;

  // JSON Format expected by Angular:
  // {"t":25.0,"h":60.0,"g":300,"ph":7.0}
  Serial.print("{\"t\":");
  Serial.print(t, 1);
  Serial.print(",\"h\":");
  Serial.print(h, 1);
  Serial.print(",\"g\":");
  Serial.print(methane, 0);
  Serial.print(",\"ph\":");
  Serial.print(ph, 2);
  Serial.println("}");
}
